#!/usr/bin/env node

import { readFileSync, writeFileSync } from "node:fs";

const [beforePath, afterPath, outputPath, nixOutputPath] =
  process.argv.slice(2);

if (!beforePath || !afterPath || !outputPath) {
  console.error(
    "usage: generate-flake-update-body.mjs <before-lock> <after-lock> <output-md> [nix-output]",
  );
  process.exit(1);
}

const before = JSON.parse(readFileSync(beforePath, "utf8"));
const after = JSON.parse(readFileSync(afterPath, "utf8"));
const nixOutput = nixOutputPath
  ? readFileSync(nixOutputPath, "utf8").trim()
  : "";

const directInputs = new Map(
  Object.entries(after.nodes.root?.inputs ?? {}).map(([inputName, nodeRef]) => [
    Array.isArray(nodeRef) ? nodeRef.at(-1) : nodeRef,
    inputName,
  ]),
);

const changedNodes = Object.entries(after.nodes)
  .flatMap(([nodeName, afterNode]) => {
    const beforeNode = before.nodes[nodeName];
    if (!beforeNode?.locked || !afterNode.locked) {
      return [];
    }

    const beforeLocked = beforeNode.locked;
    const afterLocked = afterNode.locked;
    const beforeVersion =
      beforeLocked.rev ?? beforeLocked.narHash ?? beforeLocked.lastModified;
    const afterVersion =
      afterLocked.rev ?? afterLocked.narHash ?? afterLocked.lastModified;

    if (beforeVersion === afterVersion) {
      return [];
    }

    return [
      {
        name: directInputs.get(nodeName) ?? nodeName,
        nodeName,
        direct: directInputs.has(nodeName),
        before: beforeLocked,
        after: afterLocked,
      },
    ];
  })
  .sort((left, right) => {
    if (left.direct !== right.direct) {
      return left.direct ? -1 : 1;
    }

    return left.name.localeCompare(right.name);
  });

const formatDate = (timestamp) => {
  if (!timestamp) {
    return "unknown date";
  }

  return new Date(timestamp * 1000).toISOString().slice(0, 10);
};

const shortRev = (locked) => {
  if (locked.rev) {
    return `\`${locked.rev.slice(0, 12)}\``;
  }

  if (locked.narHash) {
    return `\`${locked.narHash.slice(0, 18)}...\``;
  }

  return "unknown";
};

const repository = (locked) => {
  if (locked.type === "github" && locked.owner && locked.repo) {
    return `${locked.owner}/${locked.repo}`;
  }

  if (locked.url) {
    return locked.url;
  }

  return locked.type ?? "unknown";
};

const compareLink = (change) => {
  const { before: beforeLocked, after: afterLocked } = change;

  if (
    beforeLocked.type !== "github" ||
    afterLocked.type !== "github" ||
    beforeLocked.owner !== afterLocked.owner ||
    beforeLocked.repo !== afterLocked.repo ||
    !beforeLocked.rev ||
    !afterLocked.rev
  ) {
    return "-";
  }

  const repo = `${afterLocked.owner}/${afterLocked.repo}`;
  return `[compare](https://github.com/${repo}/compare/${beforeLocked.rev}...${afterLocked.rev})`;
};

const escapeTable = (value) => String(value).replaceAll("|", "\\|");

const lines = [
  "Weekly automated update of `flake.lock`.",
  "",
  "## Updated Inputs",
  "",
];

if (changedNodes.length === 0) {
  lines.push("No lockfile inputs changed.", "");
} else {
  lines.push(
    `Updated ${changedNodes.length} lockfile ${changedNodes.length === 1 ? "input" : "inputs"}.`,
    "",
    "| Input | Repository | From | To | Changes |",
    "| --- | --- | --- | --- | --- |",
  );

  for (const change of changedNodes) {
    lines.push(
      [
        `\`${escapeTable(change.name)}\`${change.direct ? "" : " (transitive)"}`,
        escapeTable(repository(change.after)),
        `${shortRev(change.before)} (${formatDate(change.before.lastModified)})`,
        `${shortRev(change.after)} (${formatDate(change.after.lastModified)})`,
        compareLink(change),
      ]
        .join(" | ")
        .replace(/^/, "| ")
        .replace(/$/, " |"),
    );
  }

  lines.push("");
}

lines.push(
  "## Notes",
  "",
  "- Direct flake inputs are listed first; transitive lockfile inputs are marked as such.",
  "- `Changes` links point to GitHub commit comparisons when both revisions come from the same GitHub repository.",
  "",
  "<details>",
  "<summary>Raw nix flake update output</summary>",
  "",
  "```text",
  nixOutput || "No output captured.",
  "```",
  "</details>",
  "",
  "This PR was generated by the `update-flake-lock` workflow.",
  "",
);

writeFileSync(outputPath, lines.join("\n"));
